const crypto = require('crypto');

function hashPassword(password) {
  const salt = crypto.randomBytes(16).toString('hex');
  const key = crypto.createHash('sha256').update(password + salt).digest('hex');
  return `${salt}:${key}`;
}

function verifyPassword(storedHash, inputPassword) {
  const [salt, storedKey] = storedHash.split(':');
  const newKey = crypto.createHash('sha256').update(inputPassword + salt).digest('hex');
  return newKey === storedKey;
}

// Test the functions
const password = 'mysecretpassword';
const hashedPassword = hashPassword(password);
console.log(hashedPassword);

const isValid = verifyPassword(hashedPassword, password);
console.log(isValid); // Should print: true

const invalidPassword = 'wrongpassword';
const isValid2 = verifyPassword(hashedPassword, invalidPassword);
